import{_ as a,c as s,o as t,a2 as n}from"./chunks/framework.aRVg8jgk.js";const h=JSON.parse('{"title":"Introduction to Lynq","description":"What Lynq is and why it exists — database-driven Kubernetes infrastructure, the three CRDs (LynqHub, LynqForm, LynqNode), and when to use it.","frontmatter":{"description":"What Lynq is and why it exists — database-driven Kubernetes infrastructure, the three CRDs (LynqHub, LynqForm, LynqNode), and when to use it."},"headers":[],"relativePath":"introduction.md","filePath":"introduction.md","lastUpdated":1779353865000}'),r={name:"introduction.md"};function o(i,e,l,c,p,d){return t(),s("div",null,[...e[0]||(e[0]=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /introduction.md for this page in Markdown format</div><h1 id="introduction-to-lynq" tabindex="-1">Introduction to Lynq <a class="header-anchor" href="#introduction-to-lynq" aria-label="Permalink to &quot;Introduction to Lynq&quot;">​</a></h1><p>Lynq is a Kubernetes operator that turns database rows into Kubernetes resources. When a row is active, the corresponding infrastructure exists. When the row is deactivated or deleted, the resources are cleaned up.</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span>Database row (active)    →  Deployment + Service + Ingress + ...</span></span>
<span class="line"><span>Database row (inactive)  →  resources deleted</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>No manual <code>kubectl apply</code>. No CI/CD pipeline per change. No drift.</p><h2 id="the-core-idea" tabindex="-1">The Core Idea <a class="header-anchor" href="#the-core-idea" aria-label="Permalink to &quot;The Core Idea&quot;">​</a></h2><p>Most infrastructure automation treats Git as the source of truth: write YAML, commit, wait for sync. Lynq takes a different approach — your <strong>database</strong> is the source of truth.</p><table tabindex="0"><thead><tr><th>Approach</th><th>Source of truth</th><th>How you change state</th></tr></thead><tbody><tr><td>IaC (Terraform, Pulumi)</td><td>Code in Git</td><td>Edit code, run apply</td></tr><tr><td>GitOps (Flux, Argo CD)</td><td>YAML in Git</td><td>Commit YAML, wait for sync</td></tr><tr><td><strong>Lynq (Infrastructure as Data)</strong></td><td><strong>Database rows</strong></td><td><strong>INSERT / UPDATE / DELETE</strong></td></tr></tbody></table><p>This is most useful when you already have a database that describes what should exist — a customer table, a device registry, a project list. Lynq closes the loop between that data and your cluster.</p><h2 id="three-crds" tabindex="-1">Three CRDs <a class="header-anchor" href="#three-crds" aria-label="Permalink to &quot;Three CRDs&quot;">​</a></h2><p>Lynq adds three custom resources to your cluster:</p><ul><li><strong>LynqHub</strong> — connects to your database and syncs rows at a configured interval. Defines which columns map to which template variables.</li><li><strong>LynqForm</strong> — the resource blueprint. Defines what Kubernetes resources to create for each active row, using Go templates with 200+ functions.</li><li><strong>LynqNode</strong> — one per active row per form, created automatically. Tracks reconciliation status and the lifecycle of all managed resources.</li></ul><p>The relationship: one Hub can be referenced by multiple Forms. Each active row × each Form = one LynqNode. A hub with 3 active rows and 2 forms creates 6 LynqNodes.</p><h2 id="what-gets-provisioned" tabindex="-1">What Gets Provisioned <a class="header-anchor" href="#what-gets-provisioned" aria-label="Permalink to &quot;What Gets Provisioned&quot;">​</a></h2><p>A single LynqForm can define any combination of:</p><p>Deployments · StatefulSets · DaemonSets · Services · Ingresses · ConfigMaps · Secrets · PersistentVolumeClaims · Jobs · CronJobs · HorizontalPodAutoscalers · PodDisruptionBudgets · NetworkPolicies · Namespaces · ServiceAccounts · arbitrary manifests</p><p>Resources can target the LynqNode&#39;s namespace or any other namespace via <code>targetNamespace</code>.</p><h2 id="infrastructure-as-data-in-practice" tabindex="-1">Infrastructure as Data in Practice <a class="header-anchor" href="#infrastructure-as-data-in-practice" aria-label="Permalink to &quot;Infrastructure as Data in Practice&quot;">​</a></h2><p>Operational changes become SQL statements:</p><div class="language-sql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;">-- Scale a node</span></span>
<span class="line"><span style="color:#F97583;">UPDATE</span><span style="color:#E1E4E8;"> customers </span><span style="color:#F97583;">SET</span><span style="color:#E1E4E8;"> replicas </span><span style="color:#F97583;">=</span><span style="color:#79B8FF;"> 10</span><span style="color:#F97583;"> WHERE</span><span style="color:#E1E4E8;"> id </span><span style="color:#F97583;">=</span><span style="color:#9ECBFF;"> &#39;acme-corp&#39;</span><span style="color:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">-- Enable a feature (infrastructure-level)</span></span>
<span class="line"><span style="color:#F97583;">UPDATE</span><span style="color:#E1E4E8;"> nodes </span><span style="color:#F97583;">SET</span><span style="color:#E1E4E8;"> feature_ai_assistant </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> TRUE </span><span style="color:#F97583;">WHERE</span><span style="color:#E1E4E8;"> node_id </span><span style="color:#F97583;">=</span><span style="color:#9ECBFF;"> &#39;acme-corp&#39;</span><span style="color:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">-- Traffic switch (blue-green)</span></span>
<span class="line"><span style="color:#F97583;">UPDATE</span><span style="color:#E1E4E8;"> deployments </span><span style="color:#F97583;">SET</span><span style="color:#E1E4E8;"> active_color </span><span style="color:#F97583;">=</span><span style="color:#9ECBFF;"> &#39;green&#39;</span><span style="color:#F97583;"> WHERE</span><span style="color:#E1E4E8;"> node_id </span><span style="color:#F97583;">=</span><span style="color:#9ECBFF;"> &#39;acme-corp&#39;</span><span style="color:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>The cluster syncs within the hub&#39;s <code>syncInterval</code> (default: 30 seconds). No new tooling, no context switching — operations your application already knows how to do.</p><div class="tip custom-block"><p class="custom-block-title">Combine IaD with GitOps</p><p>Use GitOps for cluster-level infrastructure (CRDs, operators, system config) and Lynq for application-level nodes (per-customer stacks, per-device configs, ephemeral environments). They complement each other.</p></div><h2 id="when-to-use-lynq" tabindex="-1">When to Use Lynq <a class="header-anchor" href="#when-to-use-lynq" aria-label="Permalink to &quot;When to Use Lynq&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Good fit when:</p><ul><li>You have a database table where each row corresponds to a Kubernetes resource set</li><li>The resource structure is repetitive across rows (same template, different variables)</li><li>Provisioning should happen automatically when data changes</li><li>You provision more than a handful of times per day</li></ul></div><div class="warning custom-block"><p class="custom-block-title">Better to use IaC if:</p><ul><li>Infrastructure changes require manual approval for every update</li><li>Changes are infrequent (once a month or less)</li><li>Deep cloud provider integrations are the primary need (Terraform is better)</li><li>Infrastructure doesn&#39;t map cleanly to database records</li></ul></div><h2 id="datasource-support" tabindex="-1">Datasource Support <a class="header-anchor" href="#datasource-support" aria-label="Permalink to &quot;Datasource Support&quot;">​</a></h2><ul><li><strong>MySQL</strong> — fully supported (v1.x)</li><li><strong>PostgreSQL</strong> — planned for v1.2</li></ul><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./quickstart">Quick Start</a> — working environment in ~5 minutes on Minikube</li><li><a href="./architecture">Architecture</a> — three-controller design, reconciliation flow, SSA engine</li><li><a href="./datasource">Datasources</a> — connecting to MySQL, value mappings, database views</li><li><a href="./advanced-use-cases">Use Cases</a> — preview environments, sandboxes, feature flags, blue-green</li></ul>`,29)])])}const y=a(r,[["render",o]]);export{h as __pageData,y as default};
